INSERT INTO umkm_kelompok_4 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (3, 'Pandawa Express', 'Layanan pengiriman paket dan barang ke luar negri yang aman, cepat, dan terpercaya. Siap melayani kebutuhan ekspedisi Anda dengan pelayanan terbaik.', 'Jasa Pengiriman', 'Yusmeri', 'Dusun Cendol Timur, RT 18 RW 03, Ngadirejo, Kec. Kromengan, Kabupaten Malang, Jawa Timur 65165', -8.129366, 112.509398, 'https://share.google/cC37tBKXNK4kSbdz1', '0857-5501-2601', 'buka 24 jam', 'Ya', 'Tidak Berkenan');
INSERT INTO umkm_kelompok_4 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (4, 'Yakcti Permak', 'Jasa Permak Pakaian Reva adalah solusi terpercaya untuk kebutuhan perbaikan dan penyesuaian pakaian Anda agar pas dan nyaman saat dikenakan. Ditangani dengan ketelitian tinggi dan kualitas jahitan yang rapi, bisa mengubah pakaian yang kebesaran, kepanjangan, atau rusak menjadi tampak seperti baru kembali.', 'Jasa Permak', 'Suciwarini', 'Dusun Dadapan, RT 01 RW 01, Ngadirejo, Kec. Kromengan, Kabupaten Malang, Jawa Timur, 65165', NULL, NULL, NULL, '6281233205782', 'buka 24 jam', 'Tidak', 'Tidak Berkenan');
INSERT INTO umkm_kelompok_4 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (5, 'Reva Queen Salon', 'Reva Queen Salon adalah pusat kecantikan profesional yang menawarkan berbagai perawatan rambut dan wajah berkualitas dengan harga terjangkau. Dikelola langsung oleh Ibu Puji Rahayu, seorang Guru SMK jurusan Tata Rias, salon ini menjamin pelayanan yang detail, modis, dan ditangani oleh ahlinya. Selain perawatan, Reva Queen Salon juga menjadi pusat pelatihan kecantikan terpercaya.', 'Jasa Usaha Kecantikan', 'Puji Rahayu', 'Jl. Merdeka Timur, Dusun Krajan, RT 09 RW 02, Ngadirejo, Kec. Kromengan, Kabupaten Malang, Jawa Timur, 65165', -8.130181, 112.51731, 'https://maps.app.goo.gl/wCrB42EJCxmfHbQv9?g_st=ac', '6282142788003', '07.00-20.00.', 'Ya', 'Sudah Ada');
INSERT INTO umkm_kelompok_4 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (6, 'Canon Fotocopy dan ATK', 'Canon Print, Fotocopy & ATK adalah unit usaha yang bergerak di bidang jasa penggandaan dokumen dan penyedia alat tulis kantor/sekolah. Usaha ini hadir untuk memberikan solusi cetak yang cepat, tajam, dan berkualitas untuk memenuhi kebutuhan tugas sekolah, administrasi kantor, serta masyarakat sekitar Ngadirejo.', 'Jasa Usaha Percetakan', 'Puji Rahayu', 'Jl. Merdeka Timur, Dusun Krajan, RT 09 RW 02, Ngadirejo, Kec. Kromengan, Kabupaten Malang, Jawa Timur, 65165', -8.130181, 112.51731, 'https://maps.app.goo.gl/wCrB42EJCxmfHbQv9?g_st=ac', '6282142788003', '07.00-20.00', 'Ya', 'Sudah Ada');
