INSERT INTO umkm_kelompok_5 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (1, 'Kue Koe', 'Menawarkan berbagai jenis kue kering seperti kue kacang dan coklat tela. tetapi, kue kering di jual dengan konsep open order. selain, kue kering usaha ini menjual mie pedas dengan level yang di mulai dari level 1-5. untuk kue di jual di setiap hari dengan berbagai topping di atasnya.', 'makanan', 'Ibu Aries', 'JL Raya, Krajan, Ngadirejo, Kromengan, Kab. Malang', -8.13242, 112.516937, 'https://maps.app.goo.gl/jFLTNYYF5a7dG7Nj7', '0858-5501-0977', '10.00 - 17.00 WIB', 'Ya', 'Dibuatkan');
INSERT INTO umkm_kelompok_5 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (2, 'Dapur Bunda', 'Menawarkan berbagai makanan dan camilan, seperti nasi catering, nasi bakar, nasi cokot, rice bowl, serta aneka jajanan harian, seperti martabak manis, martabak telur, gorengan, sosis solo, bolu, donat, dan kue basah. Pada bulan Ramadan dan Hari Raya Idulfitri, juga menyediakan takjil serta aneka kue kering, seperti nastar, kastengel, semprit, dan kuping gajah.', 'Makanan', 'Ibu Erni', 'Dsn Krajan , RT 03 rw 01 (Dadapan), desa Ngadirejo, Kec, Kromengan', -8.124466, 112.519608, 'https://maps.app.goo.gl/xsq7Ro2PxyJYJagz6?g_st=iw', '0812-16692493', '14.00 - 20.00 WIB', 'Ya', 'Tidak Berkenan');
INSERT INTO umkm_kelompok_5 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (3, 'Deka Cathering', 'Deka Katering merupakan usaha kuliner yang menyediakan berbagai pilihan makanan dan kue untuk kebutuhan sehari-hari maupun acara. Produk yang ditawarkan meliputi aneka masakan katering, kue basah seperti bikang, pastel, dan roti dengan harga mulai dari Rp3.000 per buah, serta kue kering seperti semprit, nastar, dan berbagai jenis keripik. Dengan jam operasional yang fleksibel, Deka Katering berkomitmen menghadirkan produk yang lezat, berkualitas, dan sesuai kebutuhan pelanggan.', 'Makanan', 'Ibu Mustini', 'Gg Merdeka Timur. RT.10/RW.02, Krajan, Ngadirejo, Kec Kromengan, Kabupaten Malang', -8.1305745, 112.5200073, NULL, '6285736988611', '24 jam', 'Ya', 'Tidak Berkenan');
INSERT INTO umkm_kelompok_5 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (4, 'Lumpia Rejo', 'Menawarkan camilan lumpia dengan berbagai jenis isian seperti rebung, ubi ungu, sayur ayam', 'Makanan Ringan', 'Ibu Fitriani', 'Dsn Krajan rt14, Ngan, RW.02, Krajan, Ngadirejo, Kec. Kromengan, Kabupaten Malang, Jawa Timur 65165', -8.133188, 112.513618, 'https://maps.app.goo.gl/ocpkJR7xBsc63N3u9?g_st=iw', '0895-3233-89607', '09.00 - 17.00 WIB', 'Ya', 'Dibuatkan');
INSERT INTO umkm_kelompok_5 (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (5, 'Fiona Cake', 'Fiona Cake merupakan usaha kuliner yang melayani pembuatan berbagai jenis kue berdasarkan pesanan, terutama untuk kebutuhan hajatan, acara keluarga, dan momen spesial lainnya. Produk yang ditawarkan meliputi aneka kue basah, kue kering khas Lebaran, serta paket hantaran dengan kualitas yang terjaga. Produk unggulan dari Fiona Cake adalah kue lapis dan sifon cake yang menjadi favorit pelanggan karena cita rasanya yang lezat dan teksturnya yang lembut.', 'Makanan', 'Ibu Sarianah', 'Jl HOS Cokroaminoto, Rt. 20 Rw. 03 Cendol Timur, Ngadirejo, Kec Kromengan, Kab Malang', -8.1324521, 112.5087862, 'https://maps.app.goo.gl/6vCPAj6NbuzoXoXT9', '6285730821651', '24 jam', 'Ya', 'Tidak Berkenan');
