INSERT INTO umkm_copy_of_rekap (no, nama_umkm, profil_umkm, jenis_umkm, nama_pemilik, alamat, latitude, longitude, link_gmaps, kontak, jam_operasional, berkenan, qris) VALUES (75, 'Nuri Mebel', 'Nuri Mabel merupakan usaha di bidang pengolahan dan penjualan kayu untuk kebutuhan furnitur. Kayu diperoleh dari masyarakat atau petani melalui kerja sama dengan sesama pedagang kayu. Setelah diperoleh, kayu dipotong dan diolah sesuai kebutuhan pelanggan. Jenis kayu yang tersedia cukup beragam, dengan kayu jati sebagai salah satu jenis yang paling banyak diminati karena kualitasnya yang baik. Kayu diolah menjadi bahan pembuatan berbagai produk, seperti pintu, kusen, jendela, kursi, lemari, dipan, dan berbagai perabot rumah tangga lainnya.', 'Mebel', 'Bapak Nuri', 'RT 22/RW 03, Dusun Cendol Timur, Desa Ngadirejo, Kecamatan Kromengan, Kabupaten Malang', -8.136161, 112.50847, 'https://goo.gl/maps/6rGHBy7LRyagQM8Y8?g_st=ac', '6285851471775', NULL, NULL, NULL);
